content.content:
@media (prefers-color-scheme: dark) {
  :root {
    --color-primary: #818cf8;
    --color-primary-hover: #a5b4fc;
    --color-secondary: #fbbf24;
    --color-secondary-hover: #fcd34d;

    --neutral-50: #171717;
    --neutral-100: #262626;
    --neutral-200: #404040;
    --neutral-300: #525252;
    --neutral-400: #737373;
    --neutral-500: #a3a3a3;
    --neutral-600: #d4d4d4;
    --neutral-700: #e5e5e5;
    --neutral-800: #f5f5f5;
    --neutral-900: #fafafa;

    --color-success: #4ade80;
    --color-warning: #fbbf24;
    --color-danger: #f87171;
    --color-info: #38bdf8;
  }

  body {
    color: var(--neutral-900);
    background: var(--neutral-50);
  }

  a {
    color: var(--color-primary);
  }

  pre {
    background: var(--neutral-900);
    color: var(--neutral-50);
  }

  .code-inline {
    background: var(--neutral-100);
    border-color: var(--neutral-200);
  }

  .card,
  .modal,
  .table,
  .form-control {
    background: var(--neutral-100);
    color: var(--neutral-900);
    border-color: var(--neutral-200);
  }

  .card-header,
  .modal-header,
  .modal-footer,
  .table th,
  .table td {
    border-color: var(--neutral-200);
  }

  .table th {
    background: var(--neutral-200);
  }

  .btn-ghost {
    color: var(--neutral-800);
    border-color: var(--neutral-200);
  }

  .btn-ghost:hover {
    background: var(--neutral-200);
  }

  .badge {
    background: var(--neutral-200);
    color: var(--neutral-800);
  }

  .alert,
  .alert-info,
  .alert-success,
  .alert-warning,
  .alert-danger {
    color: var(--neutral-900);
  }

  .nav a {
    color: var(--neutral-700);
  }

  .nav a.active,
  .nav a:hover {
    color: var(--color-primary);
  }

  .breadcrumbs-link {
    color: var(--neutral-700);
  }

  .breadcrumbs-current {
    color: var(--neutral-900);
  }

  .text-muted {
    color: var(--neutral-600);
  }

  .bg-neutral-100 {
    background: var(--neutral-100);
  }

  .bg-neutral-900 {
    background: var(--neutral-900);
    color: var(--neutral-50);
  }
}
